import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import '../styles/Hero.css';
import heroImage from '../assets/images/png13.jpg';

const Hero = () => {
    const { t } = useTranslation();
    const [isVisible, setIsVisible] = useState(false);

    // Keep ALL your existing 3D animation code exactly as is
    useEffect(() => {
        const timer = setTimeout(() => {
            setIsVisible(true);
        }, 100);

        // Create 3D elements when component mounts
        const createScene = () => {
            // Check if anime.js is available
            if (window.anime) {
                // Create world and particles
                const heroSection = document.querySelector('.hero-section');

                // Create scene container
                const scene = document.createElement('div');
                scene.classList.add('scene');

                // Create 3D world
                const world = document.createElement('div');
                world.classList.add('world');
                world.id = 'world';

                // Create floor
                const floor = document.createElement('div');
                floor.classList.add('floor');
                world.appendChild(floor);

                // Create cubes
                const numberOfCubes = 10;
                for (let i = 0; i < numberOfCubes; i++) {
                    const cube = document.createElement('div');
                    cube.classList.add('cube');

                    // Random properties
                    const size = Math.random() * 60 + 40;
                    cube.style.width = `${size}px`;
                    cube.style.height = `${size}px`;

                    // Position in 3D space
                    const x = (Math.random() - 0.5) * window.innerWidth;
                    const y = (Math.random() - 0.5) * window.innerHeight;
                    const z = Math.random() * -800;

                    cube.style.transform = `translate3d(${x}px, ${y}px, ${z}px)`;

                    // Create cube faces
                    const faces = ['front', 'back', 'right', 'left', 'top', 'bottom'];
                    faces.forEach(face => {
                        const element = document.createElement('div');
                        element.classList.add('cube-face', face);
                        cube.appendChild(element);
                    });

                    world.appendChild(cube);
                }

                scene.appendChild(world);

                // Create particles
                const particles = document.createElement('div');
                particles.classList.add('particles');
                particles.id = 'particles';

                // Add particles
                const numberOfParticles = 30;
                for (let i = 0; i < numberOfParticles; i++) {
                    const particle = document.createElement('div');
                    particle.classList.add('particle');

                    // Random properties
                    const size = Math.random() * 6 + 2;
                    particle.style.width = `${size}px`;
                    particle.style.height = `${size}px`;

                    const x = Math.random() * 100;
                    const y = Math.random() * 100;

                    particle.style.left = `${x}%`;
                    particle.style.top = `${y}%`;
                    particle.style.opacity = Math.random() * 0.5 + 0.2;

                    particles.appendChild(particle);
                }

                scene.appendChild(particles);

                // Add glow effects
                const glow1 = document.createElement('div');
                glow1.classList.add('glow', 'glow-1');
                const glow2 = document.createElement('div');
                glow2.classList.add('glow', 'glow-2');

                scene.appendChild(glow1);
                scene.appendChild(glow2);

                // Insert the scene as the first child of hero section
                heroSection.insertBefore(scene, heroSection.firstChild);

                // Animate elements
                // 3D world animation
                window.anime({
                    targets: '.world',
                    rotateZ: [0, 360],
                    easing: 'linear',
                    duration: 150000,
                    loop: true
                });

                // Floating animations for cubes
                window.anime({
                    targets: '.cube',
                    translateY: function() {
                        return window.anime.random(-50, 50);
                    },
                    translateZ: function() {
                        return window.anime.random(-200, 200);
                    },
                    rotateX: function() {
                        return window.anime.random(0, 360);
                    },
                    rotateY: function() {
                        return window.anime.random(0, 360);
                    },
                    easing: 'easeInOutQuad',
                    duration: function() {
                        return window.anime.random(8000, 15000);
                    },
                    delay: function() {
                        return window.anime.random(0, 2000);
                    },
                    loop: true,
                    direction: 'alternate'
                });

                // Particles animation
                window.anime({
                    targets: '.particle',
                    translateX: function() {
                        return window.anime.random(-100, 100);
                    },
                    translateY: function() {
                        return window.anime.random(-100, 100);
                    },
                    scale: function() {
                        return window.anime.random(0.5, 1.5);
                    },
                    opacity: function() {
                        return window.anime.random(0.1, 0.6);
                    },
                    easing: 'easeInOutQuad',
                    duration: function() {
                        return window.anime.random(3000, 8000);
                    },
                    delay: window.anime.stagger(50),
                    loop: true,
                    direction: 'alternate'
                });

                // Hero content animations
                window.anime({
                    targets: '.hero-title',
                    opacity: [0, 1],
                    translateY: [50, 0],
                    easing: 'easeOutExpo',
                    duration: 1500,
                    delay: 300
                });

                window.anime({
                    targets: '.hero-description',
                    opacity: [0, 1],
                    translateY: [30, 0],
                    easing: 'easeOutExpo',
                    duration: 1500,
                    delay: 500
                });

                window.anime({
                    targets: '.hero-cta-group',
                    opacity: [0, 1],
                    translateY: [30, 0],
                    easing: 'easeOutExpo',
                    duration: 1500,
                    delay: 700
                });

                window.anime({
                    targets: '.hero-stats',
                    opacity: [0, 1],
                    translateY: [30, 0],
                    easing: 'easeOutExpo',
                    duration: 1500,
                    delay: 900
                });

                // Interactive mouse movement effect
                document.addEventListener('mousemove', function(e) {
                    const mouseX = e.clientX / window.innerWidth;
                    const mouseY = e.clientY / window.innerHeight;

                    // Parallax effect on world
                    window.anime({
                        targets: '.world',
                        rotateX: 65 + (mouseY - 0.5) * 5,
                        rotateY: (mouseX - 0.5) * 10,
                        easing: 'easeOutExpo',
                        duration: 1000
                    });

                    // Moving glow with cursor
                    window.anime({
                        targets: '.glow-1',
                        translateX: (mouseX - 0.5) * 100,
                        translateY: (mouseY - 0.5) * 100,
                        easing: 'easeOutExpo',
                        duration: 1000
                    });
                });
            }
        };

        createScene();

        return () => {
            clearTimeout(timer);
            // Clean up any event listeners if needed
            document.removeEventListener('mousemove', () => {});
        };
    }, []);

    return (
        <section className={`hero-section ${isVisible ? 'visible' : ''} bg-gradient-to-br from-slate-50 to-gray-100 dark:from-gray-900 dark:to-slate-900 transition-colors duration-300`}>
            {/* 3D background will be added via JavaScript */}

            <div className="container">
                <div className="hero-content">
                    <div className="hero-text">                        
                        <h1 className="hero-title text-gray-900 dark:text-white transition-colors duration-300">
                            {t('hero.title.line1')} <br/>
                            <span className="highlight-text bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">{t('hero.title.highlight')}</span> {t('hero.title.line2')}
                        </h1>

                        <p className="hero-description text-gray-600 dark:text-gray-300 transition-colors duration-300">
                            {t('hero.description')}
                        </p>

                        <div className="hero-cta-group">
                            <Link to="/courses" className="btn btn-primary bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 text-white transition-all duration-300 hover:scale-105 hover:shadow-lg">
                                <span>{t('hero.buttons.explorePrograms')}</span>
                                <span className="material-icons">arrow_forward</span>
                            </Link>

                            <Link to="/apply" className="btn btn-outline border-2 border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-800 transition-all duration-300">
                                <span>{t('hero.buttons.applyNow')}</span>
                            </Link>
                        </div>

                        <div className="hero-stats">
                            <div className="stat-item bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm border border-gray-200/50 dark:border-gray-700/50 transition-colors duration-300">
                                <div className="stat-number text-blue-600 dark:text-blue-400">93%</div>
                                <div className="stat-label text-gray-600 dark:text-gray-400">{t('hero.stats.jobPlacement')}</div>
                            </div>

                            <div className="stat-item bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm border border-gray-200/50 dark:border-gray-700/50 transition-colors duration-300">
                                <div className="stat-number text-blue-600 dark:text-blue-400">50+</div>
                                <div className="stat-label text-gray-600 dark:text-gray-400">{t('hero.stats.industryPartners')}</div>
                            </div>

                            <div className="stat-item bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm border border-gray-200/50 dark:border-gray-700/50 transition-colors duration-300">
                                <div className="stat-number text-blue-600 dark:text-blue-400">15+</div>
                                <div className="stat-label text-gray-600 dark:text-gray-400">{t('hero.stats.yearsExcellence')}</div>
                            </div>
                        </div>
                    </div>

                    <div className="hero-image-wrapper">
                        <div className="image-card bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm border border-gray-200/50 dark:border-gray-700/50 transition-colors duration-300">
                            <img 
                                src={heroImage} 
                                alt={t('hero.imageAlt')}
                                className="hero-image"
                            />

                            <div className="image-overlay bg-gradient-to-t from-black/20 to-transparent dark:from-black/40"></div>

                            <div className="tech-tag-group">
                                <div className="tech-tag bg-blue-500 dark:bg-blue-600 text-white transition-colors duration-300">
                                    <span className="material-icons">code</span>
                                    <span>{t('hero.techTags.webDevelopment')}</span>
                                </div>
                                <div className="tech-tag bg-red-500 dark:bg-red-600 text-white transition-colors duration-300">
                                    <span className="material-icons">security</span>
                                    <span>{t('hero.techTags.cybersecurity')}</span>
                                </div>
                                <div className="tech-tag bg-green-500 dark:bg-green-600 text-white transition-colors duration-300">
                                    <span className="material-icons">analytics</span>
                                    <span>{t('hero.techTags.dataScience')}</span>
                                </div>
                                <div className="tech-tag bg-purple-500 dark:bg-purple-600 text-white transition-colors duration-300">
                                    <span className="material-icons">cloud</span>
                                    <span>{t('hero.techTags.cloudComputing')}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default Hero;
